import static org.junit.jupiter.api.Assertions.assertEquals;

import com.google.gson.Excluder;
import com.google.gson.FieldNamingStrategy;
import com.google.gson.Gson;
import com.google.gson.internal.ConstructorConstructor;
import com.google.gson.internal.bind.JsonAdapterAnnotationTypeAdapterFactory;
import com.google.gson.internal.bind.TypeAdapterFactory;
import com.google.gson.internal.ToNumberStrategy;
import com.google.gson.internal.LongSerializationPolicy;
import com.google.gson.reflect.TypeToken;
import com.google.gson.internal.ReflectionAccessFilter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.util.Collections;
import java.util.List;
import java.util.Map;

public class GsonToStringTest {

  private Gson gson;

  @BeforeEach
  public void setUp() throws Exception {
    // Prepare dependencies for Gson constructor
    Excluder excluder = Excluder.DEFAULT;
    FieldNamingStrategy fieldNamingStrategy = FieldNamingStrategy.IDENTITY;
    Map<TypeToken<?>, Object> instanceCreators = Collections.emptyMap();
    boolean serializeNulls = true;
    boolean complexMapKeySerialization = false;
    boolean generateNonExecutableGson = false;
    boolean htmlSafe = true;
    boolean prettyPrinting = false;
    boolean lenient = false;
    boolean serializeSpecialFloatingPointValues = false;
    boolean useJdkUnsafe = true;
    LongSerializationPolicy longSerializationPolicy = LongSerializationPolicy.DEFAULT;
    String datePattern = null;
    int dateStyle = 0;
    int timeStyle = 0;
    List<TypeAdapterFactory> builderFactories = Collections.emptyList();
    List<TypeAdapterFactory> builderHierarchyFactories = Collections.emptyList();
    List<TypeAdapterFactory> factoriesToBeAdded = Collections.emptyList();
    ToNumberStrategy objectToNumberStrategy = ToNumberStrategy.DEFAULT;
    ToNumberStrategy numberToNumberStrategy = ToNumberStrategy.DEFAULT;
    List<ReflectionAccessFilter> reflectionFilters = Collections.emptyList();

    // Use reflection to invoke the constructor with all parameters
    Class<Gson> clazz = Gson.class;
    gson = clazz.getDeclaredConstructor(
        Excluder.class,
        FieldNamingStrategy.class,
        Map.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        boolean.class,
        LongSerializationPolicy.class,
        String.class,
        int.class,
        int.class,
        List.class,
        List.class,
        List.class,
        ToNumberStrategy.class,
        ToNumberStrategy.class,
        List.class
    ).newInstance(
        excluder,
        fieldNamingStrategy,
        instanceCreators,
        serializeNulls,
        complexMapKeySerialization,
        generateNonExecutableGson,
        htmlSafe,
        prettyPrinting,
        lenient,
        serializeSpecialFloatingPointValues,
        useJdkUnsafe,
        longSerializationPolicy,
        datePattern,
        dateStyle,
        timeStyle,
        builderFactories,
        builderHierarchyFactories,
        factoriesToBeAdded,
        objectToNumberStrategy,
        numberToNumberStrategy,
        reflectionFilters
    );

    // Set the private final fields factories and constructorConstructor via reflection
    Field factoriesField = clazz.getDeclaredField("factories");
    factoriesField.setAccessible(true);
    factoriesField.set(gson, factoriesToBeAdded);

    Field constructorConstructorField = clazz.getDeclaredField("constructorConstructor");
    constructorConstructorField.setAccessible(true);
    constructorConstructorField.set(gson, new ConstructorConstructor(instanceCreators));
  }

  @Test
  public void testToString() throws Exception {
    String expected = "{serializeNulls:true,factories:[],instanceCreators:" + gson.constructorConstructor + "}";
    String actual = gson.toString();
    assertEquals(expected, actual);
  }
}
